head.script:
scwin.toDay = $c.date.getServerDateTime();
scwin.CREATE_AUTH = 'C' ;
scwin.RETRIEVE_AUTH = 'R' ;
scwin.UPDATE_AUTH = 'U' ;
scwin.DELETE_AUTH = 'D' ;
scwin.PRINT_AUTH = 'P' ;
scwin.EXCEL_AUTH = 'X' ;

scwin.selectedRowIndex = 0;

scwin.onpageload = function () {
    $c.gus.cfTurnCreateFlag(true); 
    scwin.f_createHeader(); 	
};

scwin.onUdcCompleted = function () {
    scwin.f_FieldClear();
    $c.gus.cfDisableObjects([ed_clntNo, ed_clntNm, ed_commCd2, ed_commNm2]);
};

scwin.ondataload = function () {

};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
scwin.f_createHeader = function () {
    ds_condition.insertRow();
    ds_condition.setRowPosition(0);
};

// 조회
scwin.f_retrieve = async function () { 
    let ret = await $c.gus.cfValidate(tb_searchCondition); 
    if (!ret) { 
        return; 
    }   

    if ($c.util.isEmpty(ed_stStockInoutDt.getValue()) || $c.util.isEmpty(ed_edStockInoutDt.getValue())) {
        $c.win.alert("적용일자은(는) 필수 입력 항목입니다.");
        return;
    }

    let e = await $c.sbm.execute(sbm_condition);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_condition_submitdone(e);
    }
};

// 그리드 데이터 엑셀로 다운
scwin.f_runExcel = async function () {
	var cntRow = ds_List1.getRowCount();
	if (cntRow > 0) {
		var cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
		if (cfrm) {
            const options = {
                fileName: "양수양도내역.xlsx"
                , sheetName: "양수양도내역"
                , type : 4 + 8 + 16
            };

            const infoArr = [];

            $c.data.downloadGridViewExcel(gr_List1, options, infoArr);
		}
    } else {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.  
    }
};

// 재고관리번호 검색 팝업창 띄우기
scwin.f_openStockNoPopUp = async function (pWinCloseTF) {
    var args = new Array();
    args[0] = ""; //재고관리번호

    var opts = {
        id : "smpPop"	
        , popupName : "재고관리번호검색팝업"
        , modal : true
        , type : "browserPopup"
        , width : 1230
        , height : 550 
        , title : "재고관리번호검색팝업"
    };

    var rtnList = await $c.win.openPopup("/ui/ds/sl/sl_101_01_08p.xml", opts, args);

    if (rtnList != null) {
        ed_takeStockMgntNo.setValue(rtnList[0]);
    } else {
        ed_takeStockMgntNo.setValue("");
    }
};

// 조회 필드 Clear
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_searchCondition, [ed_stStockInoutDt, ed_edStockInoutDt]);
    $c.gus.cfInitHidVal(tb_searchCondition);
    scwin.f_SetSrchDefault();
};

// 조회 기본값 설정
scwin.f_SetSrchDefault = function () {
    ed_stStockInoutDt.setValue(scwin.toDay); // 자바와 자바스크립트의 연결을 위해서 로드
    ed_edStockInoutDt.setValue(scwin.toDay); // 자바와 자바스크립트의 연결을 위해서 로드

    // 테스트데이터
    // ed_stStockInoutDt.setValue("20250331");
    // ed_edStockInoutDt.setValue("20250331");
};

scwin.f_OpenGridPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch, pClickTF) {
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    g_search_fag = 0;//글로벌변수: 화종조회 초기화
    switch (disGubun) {   		
        case 6: //화주 조회
            var v_clntNo = "525083";
            var v_itemCd = "SCAL_CLNT";	// 사업장 조회
            var v_wrkPlCd = "6E03";
            var v_docCd = "SCL_H01";

            pWhere = v_clntNo + "," + v_itemCd + "," + v_wrkPlCd + "," + v_docCd;
            udc_gridComCode1.setSelectId("retrieveEdiMapping");
            rtnList = await udc_gridComCode1.cfCommonPopUpAsync(
                                                                      scwin.udc_grid_takeScalClntNo_callBackFunc    // XML상의 SELECT ID	
                                                                    , pCode					                        // 화면에서의 ??? Code Element의	Value
                                                                    , pName					                        // 화면에서의 ??? Name Element의	Value
                                                                    , pClose					                    // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                                    , null					                        // 검색 결과 컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                    , "계근대;화주코드,화주명,데비스;화주코드"        // Title순서	
                                                                    , "80,150,100"					                // 보여주는 각 컬럼들의 폭	
                                                                    , "4,5,6,7,8,9,10" 					            // 컬럼중에서 숨기는	컬럼 지정	
                                                                    , pWhere					                    // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                                    , null					                        // POP-UP뛰을때 원도우의	사용자 정의	폭
                                                                    , null					                        // POP-UP뛰을때 우도우의	사용자 정의	높이	
                                                                    , null					                        // 윈도우 위치 Y좌표	
                                                                    , null					                        // 윈도우 위치 X좌표
                                                                    , null					                        // 중복체크여부	("F")
                                                                    , pAllSearch					                // 전체검색허용여부	("F")
                                                                    , "화주,화주코드,화주명"				        // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            ); 
                if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
                    ds_List1.setCellData(ds_List1.getRowPosition(), "takeScalClntNo", rtnList[0]);  
                    ds_List1.setCellData(ds_List1.getRowPosition(), "takeClntNm", rtnList[1]);
                    ds_List1.setCellData(ds_List1.getRowPosition(), "takeClntNo", rtnList[2]);
                    ds_List1.setCellData(ds_List1.getRowPosition(), "bulkTakeOverClntNo", rtnList[2]);
                } else {
                    ds_List1.setCellData(ds_List1.getRowPosition(), "takeScalClntNo", ""); 
                    ds_List1.setCellData(ds_List1.getRowPosition(), "takeClntNm", "");
                    ds_List1.setCellData(ds_List1.getRowPosition(), "takeClntNo", "");
                    ds_List1.setCellData(ds_List1.getRowPosition(), "bulkTakeOverClntNo", "");    
                }						
        break; 
    }
};

// 양수도 내역 저장 .
scwin.f_InheritSave = async function () {
    if (ds_List1.getModifiedIndex().length != 0) {
        let ret = await $c.gus.cfValidate([gr_List1]); 
        if (!ret) { 
            return; 
        }

        let msg = "양수양도내역의 %1번째 데이터에서 %2은(는) 필수 입력 항목입니다."

        for (var i = 0; i < ds_List1.getRowCount(); i++) {

            if($c.util.isEmpty(ds_List1.getCellData(i, "inputClsCd"))) {
                await $c.gus.cfAlertMsg(msg, [i+1, "입력구분"]);
                gr_List1.setFocusedCell(i, "inputClsCd", true);
                return;
            }

            if($c.util.isEmpty(ds_List1.getCellData(i, "handStockMgntNo"))) {
                await $c.gus.cfAlertMsg(msg, [i+1, "재고관리번호"]);
                gr_List1.setFocusedCell(i, "handStockMgntNo", true);
                return;
            }

            if($c.util.isEmpty(ds_List1.getCellData(i, "inheritAdptDt"))) {
                await $c.gus.cfAlertMsg(msg, [i+1, "양수일자"]);
                gr_List1.setFocusedCell(i, "inheritAdptDt", true);
                return;
            }

            if($c.util.isEmpty(ds_List1.getCellData(i, "takeScalClntNo"))) {
                await $c.gus.cfAlertMsg(msg, [i+1, "계근대화주"]);
                gr_List1.setFocusedCell(i, "takeScalClntNo", true);
                return;
            }

            if (ds_List1.getRowStatus(i) != "R") { 
                if (ds_List1.getCellData(i, "inputClsCd") == "2") {
                    $c.win.alert((i+1) + "행은 재고합산건이므로 양수양도 저장이 불가능합니다.");
                    return;
                }
            }

        }

        let saveChk = await $c.win.confirm(MSG_CM_CRM_001);
        if (saveChk) {  // 저장하시겠습니까?
            let e = await $c.sbm.execute(sbm_save);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_save_submitdone(e);
            }
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["양수양도등록"]); // @은(는) 변경된 사항이 없습니다
    }
};

// 재고합산 내역 저장 .
scwin.f_TranSave = async function () {
    if (ds_List1.getModifiedIndex().length != 0) {
      //  let ret = await $c.gus.cfValidate([gr_List1]); 
     //   if (!ret) { 
       //     return; 
      //  }
        let msg = "양수양도내역의 %1번째 데이터에서 %2은(는) 필수 입력 항목입니다."
        for (var i = 0; i < ds_List1.getRowCount(); i++) {
            if (ds_List1.getRowStatus(i) != "R") {

                if($c.util.isEmpty(ds_List1.getCellData(i, "inputClsCd"))) {
                    await $c.gus.cfAlertMsg(msg, [i+1, "입력구분"]);
                    gr_List1.setFocusedCell(i, "inputClsCd", true);
                    return;
                }

                if($c.util.isEmpty(ds_List1.getCellData(i, "handStockMgntNo"))) {
                    await $c.gus.cfAlertMsg(msg, [i+1, "재고관리번호"]);
                    gr_List1.setFocusedCell(i, "handStockMgntNo", true);
                    return;
                }

                if($c.util.isEmpty(ds_List1.getCellData(i, "inheritAdptDt"))) {
                    await $c.gus.cfAlertMsg(msg, [i+1, "양수일자"]);
                    gr_List1.setFocusedCell(i, "inheritAdptDt", true);
                    return;
                }

                if($c.util.isEmpty(ds_List1.getCellData(i, "takeScalClntNo"))) {
                    await $c.gus.cfAlertMsg(msg, [i+1, "양수화주명"]);
                    gr_List1.setFocusedCell(i, "takeScalClntNo", true);
                    return;
                }

                if (ds_List1.getRowStatus(i) != "R") { 
                    if (ds_List1.getCellData(i, "inputClsCd") == "1") {
                        $c.win.alert((i+1) + "행은 재고합산건이므로 양수양도 저장이 불가능합니다.");
                        return;
                    }
                }

          /*      if (ds_List1.getCellData(i, "inputClsCd") == "1") {
                    $c.win.alert((i+1) + "행은 양수양도건이므로 재고합산 저장이 불가능합니다.");
                    return;
                } */

                if (ds_List1.getCellData(i, "takeStockMgntNo") == "1") {
                    $c.win.alert((i+1) + "행은 양수재고번호가 존재하지 않아 저장이 불가능합니다.");
                    return;
                }

            }

        }


        let saveChk = await $c.win.confirm(MSG_CM_CRM_001);
        if (saveChk) {  // 저장하시겠습니까?
            let e = await $c.sbm.execute(sbm_save2);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_save2_submitdone(e);
            }
        }

    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["양수양도등록"]); // @은(는) 변경된 사항이 없습니다
    }		
};

scwin.f_openCommPopUpGrid = async function (disGubun, row, closeYn) {
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    switch (disGubun) {   
        case 1:
            var args = new Array();
            args[0] = ""; //재고관리번호

            var opts = {
                id : "smpPop"	
                , popupName : "재고관리번호검색팝업"
