                ds_List1.setCellData(ds_List1.getRowPosition(), "commNm", rtnList[8]);
                ds_List1.setCellData(ds_List1.getRowPosition(), "commCd", rtnList[9]);
                ds_List1.setCellData(ds_List1.getRowPosition(), "arvIntendDt", rtnList[5]);
                ds_List1.setCellData(ds_List1.getRowPosition(), "handScalClntNo", rtnList[10]);
                ds_List1.setCellData(ds_List1.getRowPosition(), "scalCommCd", rtnList[11]);
                ds_List1.setCellData(ds_List1.getRowPosition(), "stockStdAdptDt", rtnList[12]);
                ds_List1.setCellData(ds_List1.getRowPosition(), "handStrRateAdptDt", rtnList[12]);
                ds_List1.setCellData(ds_List1.getRowPosition(), "takeStockStdAdptDt", rtnList[12]);
