};

// 행추가
scwin.f_AddRow = function () {
    var rowIndex = ds_List1.insertRow();
    ds_List1.setRowPosition(rowIndex);
};

// 행삭제
scwin.f_DelRow = function () {
    var row = ds_List1.getRowPosition();
    if (ds_List1.getRowStatus(row) == "C") {
        ds_List1.removeRow(row);
    } else {
        ds_List1.deleteRow(row);
    }
};

// 취소
scwin.f_CanRow = function () {
    var row = ds_List1.getRowPosition();
    if (ds_List1.getRowStatus(row) == "C") {
        ds_List1.removeRow(row);
    } else {
        ds_List1.undoRow(row);
    }
};

scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  	// 선언부
	var rtnList;  // 공통POP-UP -> 요청화면 
	var pWhere;		// 조회조건

	switch (disGubun) {
  		case 1: // 거래처 팝업	
  			var v_clntNo = "525083";
  			var v_itemCd = "SCAL_CLNT";	// 사업장 조회
  			var v_wrkPlCd = "6E03";
  			var v_docCd = "SCL_H01";

  			pWhere = v_clntNo + "," + v_itemCd + "," + v_wrkPlCd + "," + v_docCd;
            udc_clntNo.setSelectId("retrieveEdiMapping");
            rtnList = await udc_clntNo.cfCommonPopUpAsync(
                                                              ''	                                    // XML상의 SELECT ID	
                                                            , pCode					                    // 화면에서의 ??? Code Element의	Value
                                                            , pName					                    // 화면에서의 ??? Name Element의	Value
                                                            , pClose					                // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                            , null					                    // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                            , "계근대;화주코드,화주명,데비스;화주코드"    // Title순서	
                                                            , "80,150,100"					            // 보여주는 각 컬럼들의 폭	
                                                            , "4,5,6,7,8,9,10" 					        // 컬럼중에서 숨기는	컬럼 지정	
                                                            , pWhere					                // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                            , null					                    // POP-UP뛰을때 원도우의	사용자 정의	폭
                                                            , null					                    // POP-UP뛰을때 우도우의	사용자 정의	높이	
                                                            , null					                    // 윈도우 위치 Y좌표	
                                                            , null					                    // 윈도우 위치 X좌표
                                                            , null					                    // 중복체크여부	("F")
                                                            , pAllSearch					            // 전체검색허용여부	("F")
                                                            , "화주,화주코드,화주명"				     // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  								                        ); 

            if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
                ed_scalClntNo.setValue(rtnList[0]);
                ed_clntNm.setValue(rtnList[1]);
                ed_clntNo.setValue(rtnList[2]);
            } else {
                ed_scalClntNo.setValue("");
                ed_clntNm.setValue("");
                ed_clntNo.setValue("");
            }
        break;


        case 4: // 거래처 팝업	
  			var v_clntNo = "525083";
  			var v_itemCd = "SCAL_COMM";	// 사업장 조회
  			var v_wrkPlCd = "6E03";
  			var v_docCd = "SCL_H01";

  			pWhere = v_clntNo + "," + v_itemCd + "," + v_wrkPlCd + "," + v_docCd;
            udc_commCd2.setSelectId("retrieveEdiMapping"); 
            rtnList = await udc_commCd2.cfCommonPopUpAsync(
                                                              ''                                        // XML상의 SELECT ID	
  									                        , pCode					                    // 화면에서의 ??? Code Element의	Value
                                                            , pName					                    // 화면에서의 ??? Name Element의	Value
                                                            , pClose					                // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                            , null					                    // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                            , "계근대;품명코드,품명,데비스;품명코드"      // Title순서	
                                                            , "80,150,100"					            // 보여주는 각 컬럼들의 폭	
                                                            , "4,5,6,7,8,9,10" 					        // 컬럼중에서 숨기는	컬럼 지정	
                                                            , pWhere					                // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                            , null					                    // POP-UP뛰을때 원도우의	사용자 정의	폭
                                                            , null					                    // POP-UP뛰을때 우도우의	사용자 정의	높이	
                                                            , null					                    // 윈도우 위치 Y좌표	
                                                            , null					                    // 윈도우 위치 X좌표
                                                            , null					                    // 중복체크여부	("F")
                                                            , pAllSearch					            // 전체검색허용여부	("F")
                                                            , "품목,품명코드,품명"				         // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  									                    ); 
            if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
                ed_scalCommCd2.setValue(rtnList[0]);
                ed_commNm2.setValue(rtnList[1]);
                ed_commCd2.setValue(rtnList[2]);
            } else {
                ed_scalCommCd2.setValue("");
                ed_commNm2.setValue("");
                ed_commCd2.setValue("");
            }						
        break;
	}
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.fn_formatDate = function(data, formattedData, rowIndex, colIndex) {
    if (!data || data.length !== 8) return data;
    return data.substr(0, 4) + "/" + data.substr(4, 2) + "/" + data.substr(6, 2);
};

