scwin.sbm_condition_submitdone = function (e) {
    if (ds_List1.getRowCount() == 0) {
        $c.win.alert(MSG_CM_WRN_002);
    }
    const OUT_DS1 = e.responseJSON.OUT_DS1.sort((a, b) => {
        let valA = a.inheritAdptDt;
        let valB = b.inheritAdptDt;
        if (valA < valB) return 1;
        if (valA > valB) return -1;
        return 0;
    });
    ds_List1.setJSON(OUT_DS1);
	gr_List1.setFocusedCell(0,0);
    totalRows.setValue(ds_List1.getRowCount());
};

scwin.sbm_save_submitdone = function (e) {
    $c.win.alert(MSG_CM_INF_001);	 // 성공적으로 저장하였습니다 
	scwin.f_retrieve(); 
};

