};


scwin.ds_List1_oncelldatachange = async function (info) {
    const colid = info.colID;
    const rowIndex = info.rowIndex;
    if (colid == "inheritWt") { // 중량
        if (Number(ds_List1.getCellData(rowIndex,"restWt")) < Number(ds_List1.getCellData(rowIndex,"inheritWt"))) {
            if (ds_List1.getCellData(rowIndex,"inputClsCd") == 1) {
                $c.win.alert("양수도 물량이 현재고량을 초과하였습니다.");				
            } else if (ds_List1.getCellData(rowIndex,"inputClsCd") == 2) {
                $c.win.alert("합산 물량이 현재고량을 초과하였습니다.");
            }

        }	
    } else if (colid == "takeScalClntNo") { // 계근대화주
        if (ds_List1.getCellData(rowIndex,"takeStockMgntNo") != "") {
            $c.win.alert("양수재고번호가 존재하므로 입력이 불가능합니다.");
            ds_List1.setCellData(rowIndex, "takeScalClntNo", ds_List1.getOriginalCellData(rowIndex, "takeScalClntNo")); 
            return;
        }
        if (ds_List1.getCellData(rowIndex,colid) != "") {
            if (ds_List1.getCellData(rowIndex,colid) != ds_List1.getOriginalCellData(rowIndex, "takeScalClntNo")) {  // if (ds_List1.getCellData(rowIndex,colid) != olddata)
                scwin.f_OpenGridPopUp(6, ds_List1.getCellData(rowIndex,colid),'' ,'T','T');
            }
        } else {
            ds_List1.setCellData(ds_List1.getRowPosition(),"takeScalClntNo", "");                  
            ds_List1.setCellData(ds_List1.getRowPosition(),"takeClntNm", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"takeClntNo", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"bulkTakeOverClntNo", "");
        }
    } else if (colid == "handStockMgntNo") { // 재고관리번호
        if (ds_List1.getCellData(rowIndex,"handStockMgntNo") == ds_List1.getOriginalCellData(rowIndex, "handStockMgntNo")) {    // if (ds_List1.getCellData(rowIndex,"handStockMgntNo") == olddata)
            return;
        }

        var args = new Array();
        var rtnList = new Array();
        args[0] = ""; // 재고관리번호
        args[1] = "";
        args[2] = ds_List1.getCellData(rowIndex,"handStockMgntNo");        

        var opts = {
            id : "smpPop"	
            , popupName : "재고관리번호검색팝업"
            , modal : true
            , type : "browserPopup"
            , width : 1230
            , height : 550 
            , title : "재고관리번호검색팝업"
        };

        rtnList = await $c.win.openPopup("/ui/ds/sl/sl_101_01_08p.xml", opts, args);   

        if (rtnList != null) {
            ds_List1.unbind("oncelldatachange");
            ds_List1.setCellData(ds_List1.getRowPosition(),"handStockMgntNo", rtnList[0]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"vsslCd", rtnList[6]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"vsslNm", rtnList[1]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"restWt", rtnList[3]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"handClntNo", rtnList[7]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"bulkHandOverClntNo", rtnList[7]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"handClntNm", rtnList[4]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"commNm", rtnList[8]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"commCd", rtnList[9]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"arvIntendDt", rtnList[5]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"handScalClntNo", rtnList[10]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"scalCommCd", rtnList[11]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"stockStdAdptDt", rtnList[12]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"handStrRateAdptDt", rtnList[12]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"takeStockStdAdptDt", rtnList[12]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"inheritAdptDt", rtnList[12]);
            ds_List1.setCellData(ds_List1.getRowPosition(),"takeStrRateAdptDt", rtnList[13]);
            ds_List1.bind("oncelldatachange", scwin.ds_List1_oncelldatachange);
            // 통관일자 콤보
            sbm_customsDt.action = "/ds.sl.RetrieveScaleCustomsDtCMD.do?stockMgntNo=" + rtnList[0];
            let e = await $c.sbm.execute(sbm_customsDt);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            }
        } else { 
            ds_List1.unbind("oncelldatachange");
            ds_List1.setCellData(ds_List1.getRowPosition(),"handStockMgntNo", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"vsslCd", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"vsslNm", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"restWt", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"handClntNo", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"bulkHandOverClntNo", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"handClntNm", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"commNm", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"commCd", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"arvIntendDt", "");
            ds_List1.setCellData(ds_List1.getRowPosition(),"handScalClntNo","");
            ds_List1.setCellData(ds_List1.getRowPosition(),"scalCommCd","");
            ds_List1.setCellData(ds_List1.getRowPosition(),"stockStdAdptDt","");
            ds_List1.setCellData(ds_List1.getRowPosition(),"handStrRateAdptDt","");
            ds_List1.setCellData(ds_List1.getRowPosition(),"takeStockStdAdptDt","");
            ds_List1.setCellData(ds_List1.getRowPosition(),"inheritAdptDt","");
            ds_List1.setCellData(ds_List1.getRowPosition(),"takeStrRateAdptDt","");
            ds_List1.bind("oncelldatachange", scwin.ds_List1_oncelldatachange);
        }
    }

};  


