scwin.gr_List1_onviewchange = function (info) {
    var colId = info.colId;
    var row = info.rowIndex;
    var newValue = info.newValue;
    var oldValue = info.oldValue;

	 if (colId == "inputClsCd") {
		if (ds_List1.getCellData(row, "inputClsCd") == 2) { // 재고합산
            gr_List1.setCellReadOnly(row, "takeStockMgntNo", false); // 재고관리;번호"
            gr_List1.setCellReadOnly(row, "takeScalClntNo", true);   // 계근대;화주
		} else { // 양수양도
            gr_List1.setCellReadOnly(row, "takeStockMgntNo", true);  // 재고관리;번호"
            gr_List1.setCellReadOnly(row, "takeScalClntNo", false);  // 계근대;화주

			ds_List1.setCellData(ds_List1.getRowPosition(), "takeStockMgntNo", "");
			ds_List1.setCellData(ds_List1.getRowPosition(), "takeClntNo", "");
			ds_List1.setCellData(ds_List1.getRowPosition(), "takeClntNm", "");
			ds_List1.setCellData(ds_List1.getRowPosition(), "takeScalClntNo", "");
			ds_List1.setCellData(ds_List1.getRowPosition(), "bulkTakeOverClntNo", "");
		}		
	}	
};

scwin.gr_List1_onrowindexchange = function (rowIndex, oldRow) {
	if (ds_List1.getRowStatus(rowIndex) == "C") {
		if (ds_List1.getCellData(rowIndex, "inputClsCd") == "2") {
            gr_List1.setCellReadOnly(rowIndex, "takeStockMgntNo", false); // 재고관리;번호"
            gr_List1.setCellReadOnly(rowIndex, "takeScalClntNo", true);   // 계근대;화주
		} else {
            gr_List1.setCellReadOnly(rowIndex, "takeStockMgntNo", true);  // 재고관리;번호"
            gr_List1.setCellReadOnly(rowIndex, "takeScalClntNo", false);  // 계근대;화주
		}	
        gr_List1.setCellReadOnly(rowIndex, "handStockMgntNo", false);
        gr_List1.setCellReadOnly(rowIndex, "inputClsCd", false);
	} else {
        gr_List1.setCellReadOnly(rowIndex, "takeStockMgntNo", true);
        gr_List1.setCellReadOnly(rowIndex, "takeScalClntNo", true);
        gr_List1.setCellReadOnly(rowIndex, "handStockMgntNo", true);
        gr_List1.setCellReadOnly(rowIndex, "inputClsCd", true);
	}
};


